# Author: Marco Mignacca
# -------------------------------------------------------------------------

import numpy as np
import matplotlib.pyplot as plt
from cross_validation import cross_validation

# Parameters
num_vids = 20
T = 80
r = 5
p = 20
P = np.arange(0.001, 1.001, 0.001)
k = 4
c = 100
d_star = 30
dim = 426 * 240

# Events matrix: shape (3500, num_vids), 0-based row indexing
frames = np.zeros((3500, num_vids))

frames[756 - T - 1, 0] = 1;   frames[921 - 1, 0] = 1
