# Run cross-validation
optimal_deltas, avg_validation_error, avg_training_error = \
    cross_validation(frames, num_vids, P, k, c, d_star)

print(f'Optimal Thresholds: {optimal_deltas}')
print(f'Average Errors: {avg_validation_error}')

# Plot mean training error curve
mean_train_err = np.mean(avg_training_error, axis=0)
best_idx = np.argmin(mean_train_err)

fig, ax = plt.subplots()
ax.plot(P, mean_train_err, linewidth=2)
ax.scatter(P[best_idx], mean_train_err[best_idx], s=100, zorder=5)
ax.set_xlabel('Threshold Values')
ax.set_ylabel('Error')
ax.set_xlim([0, 1])
ax.set_ylim([0, np.max(mean_train_err) + 10])
ax.tick_params(labelsize=16)

plt.show()
